import play.api.mvc._
import slick.jdbc.MySQLProfile.api._
import models.Product

class ProductSearchController extends Controller {

  def searchProducts = Action { implicit request =>
    val searchParams = request.queryString
    val query = sql"""
      SELECT * FROM products
      WHERE name LIKE '%' || ${searchParams("name").headOption.getOrElse("")} || '%'
      AND category = ${searchParams("category").headOption.getOrElse("")}
      AND price >= ${searchParams("minPrice").headOption.getOrElse("0")}
      AND price <= ${searchParams("maxPrice").headOption.getOrElse("Double.MaxValue")}
    """.as[Product]
    Ok(views.html.productSearch(query))
  }
